    def __init__(self, data: List[Any]):
        self.data = data

    def __len__(self):
        return len(self.data)

    def __getitem__(self, index):
        return self.data[index]

def dict_data_collator(batch: List[MutableMapping]) -> UserDict:
    ret = UserDict({})
    for k in batch[0].keys():
